    I_Na_tot = I_Na_tot_junc + I_Na_tot_sl;
    I_Cl_tot = I_ClCa+I_Clbk;
    I_Ca_tot = I_Ca_tot_junc+I_Ca_tot_sl;
    I_tot = I_Na_tot+I_Cl_tot+I_Ca_tot+I_K_tot;
    finavalu[offset_39] = -(I_tot-I_app);

    finavalu[offset_41] = 0.0f;
    finavalu[offset_42] = 0.0f;
}

__kernel void kernel_gpu_opencl(int timeinst,
                                __global fp *initvalu,
                                __global fp *finavalu,
                                __global fp *parameter,
                                __global fp *com) {

    int gid = get_global_id(0);
    if (gid != 0) return;

    fp t = (fp)timeinst;

    int initvalu_offset_ecc = 0;
    int parameter_offset_ecc = 0;
    int initvalu_offset_Dyad = 46;
    int parameter_offset_Dyad = 1;
    int initvalu_offset_SL = 61;
    int parameter_offset_SL = 6;
    int initvalu_offset_Cyt = 76;
    int parameter_offset_Cyt = 11;

    fp JCaDyad;
    fp JCaSL;
    fp JCaCyt;

    fp CaDyad = initvalu[35]*1e3f;
    fp CaSL = initvalu[36]*1e3f;
    fp CaCyt = initvalu[37]*1e3f;

    ecc(t, initvalu, initvalu_offset_ecc, parameter, parameter_offset_ecc, finavalu);

    JCaDyad = cam(t, initvalu, initvalu_offset_Dyad, parameter, parameter_offset_Dyad, finavalu, CaDyad);
    JCaSL   = cam(t, initvalu, initvalu_offset_SL,   parameter, parameter_offset_SL,   finavalu, CaSL);
    JCaCyt  = cam(t, initvalu, initvalu_offset_Cyt,  parameter, parameter_offset_Cyt,  finavalu, CaCyt);

    com[0] = JCaDyad;
    com[1] = JCaSL;
    com[2] = JCaCyt;
}
